import { useState } from 'react';

export function CurrencyInput({ value, onChange, currency = 'USD', locale = 'en-US' }: { value: number; onChange: (v: number) => void; currency?: string; locale?: string }) {
  const [display, setDisplay] = useState('');
  const [editing, setEditing] = useState(false);

  const formatter = new Intl.NumberFormat(locale, { style: 'currency', currency });

  return (
    <input
      type="text"
      inputMode="decimal"
      value={editing ? display : formatter.format(value)}
      onFocus={() => { setDisplay(String(value)); setEditing(true); }}
      onChange={(e) => setDisplay(e.target.value)}
      onBlur={() => {
        setEditing(false);
        const num = parseFloat(display.replace(/[^0-9.-]/g, ''));
        if (!isNaN(num)) onChange(num);
      }}
      className="w-full min-h-11 rounded border px-3 text-base tabular-nums"
    />
  );
}

