import { useState, useRef } from 'react';

export function MentionComposer({ users, onSend }: { users: { id: string; name: string }[]; onSend: (text: string) => void }) {
  const [value, setValue] = useState('');
  const [mentioning, setMentioning] = useState<string | null>(null);

  const onChange = (v: string) => {
    setValue(v);
    const match = v.match(/@(\w*)$/);
    setMentioning(match ? match[1] : null);
  };

  const filtered = users.filter((u) => u.name.toLowerCase().includes((mentioning ?? '').toLowerCase()));

  return (
    <div className="relative">
      {mentioning !== null && filtered.length > 0 && (
        <ul className="absolute bottom-full left-0 mb-1 max-h-48 overflow-y-auto rounded border bg-white shadow-lg min-w-[200px]">
          {filtered.map((u) => (
            <li key={u.id}>
              <button
                onClick={() => {
                  setValue((v) => v.replace(/@\w*$/, `@${u.name} `));
                  setMentioning(null);
                }}
                className="block w-full text-left min-h-11 px-3 hover:bg-neutral-50"
              >@{u.name}</button>
            </li>
          ))}
        </ul>
      )}
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        rows={1}
        className="w-full rounded border p-3 text-base resize-none"
      />
    </div>
  );
}

