  const years = Array.from({ length: 100 }, (_, i) => new Date().getFullYear() - i);

  return (
    <div className="flex gap-2">
      <select value={m || ''} onChange={(e) => onChange(`${y || '1990'}-${e.target.value}-${d || '01'}`)} aria-label="Month" className="min-h-10 rounded border px-2">
        <option value="">Month</option>
        {Array.from({ length: 12 }, (_, i) => (
          <option key={i} value={String(i + 1).padStart(2, '0')}>{new Date(2024, i).toLocaleString('en', { month: 'long' })}</option>
        ))}
      </select>
      <select value={d || ''} onChange={(e) => onChange(`${y || '1990'}-${m || '01'}-${e.target.value}`)} aria-label="Day" className="min-h-10 rounded border px-2">
        <option value="">Day</option>
        {Array.from({ length: 31 }, (_, i) => <option key={i}>{String(i + 1).padStart(2, '0')}</option>)}
      </select>
      <select value={y || ''} onChange={(e) => onChange(`${e.target.value}-${m || '01'}-${d || '01'}`)} aria-label="Year" className="min-h-10 rounded border px-2">
        <option value="">Year</option>
        {years.map((y) => <option key={y}>{y}</option>)}
      </select>
    </div>
  );
}

