import { useState } from 'react';
import { Play } from 'lucide-react';

export function LazyYouTube({ videoId, title }: { videoId: string; title: string }) {
  const [loaded, setLoaded] = useState(false);
  const thumb = `https://i.ytimg.com/vi/${videoId}/hqdefault.jpg`;

  if (!loaded) {
    return (
      <button
        type="button"
        onClick={() => setLoaded(true)}
        aria-label={`Play video: ${title}`}
        className="relative w-full aspect-video group"
      >
        <img src={thumb} alt={title} className="absolute inset-0 h-full w-full object-cover rounded" />
        <div className="absolute inset-0 flex items-center justify-center bg-black/30 group-hover:bg-black/40 rounded">
          <div className="flex h-16 w-16 items-center justify-center rounded-full bg-red-600">
            <Play className="h-7 w-7 text-white ml-1" />
          </div>
        </div>
      </button>
    );
  }

  return (
    <iframe
      src={`https://www.youtube.com/embed/${videoId}?autoplay=1`}
      title={title}
      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
      allowFullScreen
      className="w-full aspect-video rounded border-0"
    />
  );
}

import { useEffect, useRef, useState } from 'react';

export function SubNavWithHorizontalScrollSnapVisibl() {
  const rootRef = useRef<HTMLDivElement>(null);
  const [compact, setCompact] = useState(false);

  useEffect(() => {
    const node = rootRef.current;
    if (!node) return;
    const observer = new ResizeObserver(([entry]) => setCompact(entry.contentRect.width < 560));
    observer.observe(node);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={rootRef} data-compact={compact} className="grid gap-3 data-[compact=true]:grid-cols-1 data-[compact=false]:grid-cols-[16rem_1fr]">
      <nav aria-label="Section navigation" className="overflow-x-auto whitespace-nowrap">{/* actions remain reachable on touch and keyboard */}</nav>
      <main className="min-w-0">{/* Sub-nav with horizontal scroll snap + visible scroll indicators */}</main>
    </section>
  );
}

